function.arguments:
{"action": "write_file", "name": "n8n-workflow-integration", "file_path": "references/hermes-notification-workflow.json", "file_content": "{
  "name": "Hermes Notification Workflow",
  "nodes": [
    {
      "name": "Webhook",
      "type": "n8n-nodes-base.webhook",
      "position": [250, 300],
      "parameters": {
        "path": "hermes-webhook",
        "options": {}
      },
      "webhookId": "hermes-webhook"
    },
    {
      "name": "Switch",
      "type": "n8n-nodes-base.switch",
      "position": [450, 300],
      "parameters": {
        "rules": {
          "rules": [
            {
              "conditions": {
                "string": [
                  {
                    "value1": "={{$json.channel}}",
                    "operation": "equals",
                    "value2": "telegram"
                  }
                ]
              }
            },
            {
              "conditions": {
                "string": [
                  {
                    "value1": "={{$json.channel}}",
                    "operation": "equals",
                    "value2": "email"
                  }
                ]
              }
            }
          ]
        }
      }
    },
    {
      "name": "Telegram",
      "type": "n8n-nodes-base.telegram",
      "position": [650, 200],
      "parameters": {
        "resource": "message",
        "operation": "sendMessage",
        "chatId": "={{$env.TELEGRAM_CHAT_ID}}",
        "text": "={{$json.message}}"
      }
    },
    {
      "name": "Email",
      "type": "n8n-nodes-base.emailSend",
      "position": [650, 400],
      "parameters": {
        "fromEmail": "={{$env.EMAIL_FROM}}",
        "toEmail": "={{$env.EMAIL_TO}}",
        "subject": "Hermes Notification",
        "text": "={{$json.message}}"
      }
    },
    {
      "name": "Respond to Webhook",
      "type": "n8n-nodes-base.respondToWebhook",
      "position": [850, 300],
      "parameters": {
        "respondWith": "lastNode",
        "options": {}
      }
    }
  ],
  "connections": {
    "Webhook": {
      "main": [
        [
          {
            "node": "Switch",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Switch": {
      "main": [
        [
          {
            "node": "Telegram",
            "type": "main",
            "index": 0
          }
        ],
        [
          {
            "node": "Email",
            "type": "main",
            "index": 1
          }
        ]
      ]
    },
    "Telegram": {
      "main": [
        [
          {
            "node": "Respond to Webhook",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Email": {
      "main": [
        [
          {
            "node": "Respond to Webhook",
            "type": "main",
            "index": 0
          }
        ]
      ]
    }
  },
  "settings": {
    "executionOrder": "v1"
  },
  "staticData": null,
  "triggerCount": 1
}"}
